import{_ as a,o as t,c as s,a2 as n}from"./chunks/framework.B8zgMDLd.js";const u=JSON.parse('{"title":"File Layout","description":"","frontmatter":{},"headers":[],"relativePath":"reference/file-layout.md","filePath":"reference/file-layout.md"}'),o={name:"reference/file-layout.md"};function i(r,e,l,p,d,c){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="file-layout" tabindex="-1">File Layout <a class="header-anchor" href="#file-layout" aria-label="Permalink to &quot;File Layout&quot;">​</a></h1><p>Tolaria is not opinionated about folder structure. It finds notes recursively across the whole vault, stores new notes in the root by default, and uses types and relationships for real organization.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my-vault/</span></span>
<span class="line"><span>  project-alpha.md</span></span>
<span class="line"><span>  weekly-review.md</span></span>
<span class="line"><span>  research/</span></span>
<span class="line"><span>    source-notes.md</span></span>
<span class="line"><span>  attachments/</span></span>
<span class="line"><span>    diagram.png</span></span>
<span class="line"><span>    source.pdf</span></span>
<span class="line"><span>  project.md</span></span>
<span class="line"><span>  person.md</span></span>
<span class="line"><span>  views/</span></span>
<span class="line"><span>    active-projects.yml</span></span></code></pre></div><h2 id="root-notes" tabindex="-1">Root Notes <a class="header-anchor" href="#root-notes" aria-label="Permalink to &quot;Root Notes&quot;">​</a></h2><p>Tolaria works well with a flat vault. Folders are optional and can be useful for compatibility with other tools, but they are not required for people, projects, topics, or any other note category.</p><p>Type is not inferred from folder location. It comes from frontmatter, and relationships are expressed with wikilinks in fields. That is what Tolaria uses for the sidebar, Properties panel, search, custom views, and neighborhood navigation.</p><h2 id="special-folders" tabindex="-1">Special Folders <a class="header-anchor" href="#special-folders" aria-label="Permalink to &quot;Special Folders&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Folder</th><th>Purpose</th></tr></thead><tbody><tr><td><code>views/</code></td><td>Saved custom views.</td></tr><tr><td><code>attachments/</code></td><td>Images and other attached files.</td></tr></tbody></table><p>PDFs, images, and other non-Markdown files stay as normal files. Folder browsing can show them in place, and Settings controls whether PDFs, images, and unsupported files appear in All Notes.</p><p>Whiteboards are Markdown files with durable tldraw data, so they belong with notes rather than in <code>attachments/</code>.</p><p>Type definitions are Markdown notes with <code>type: Type</code> in frontmatter. New type documents are normal notes, and existing type documents in older folders still work.</p><h2 id="git-files" tabindex="-1">Git Files <a class="header-anchor" href="#git-files" aria-label="Permalink to &quot;Git Files&quot;">​</a></h2><p>If the vault is a Git repository, <code>.git/</code> belongs to Git. Tolaria reads Git state but does not treat <code>.git/</code> as notes.</p>`,13)])])}const f=a(o,[["render",i]]);export{u as __pageData,f as default};
